143	/*
144	 * QuickJS-NG attaches the "stack" property to an Error object too early,
145	 * which results in empty stack trace when called from C code.
146	 * Removing it allows the stack to be attached later during unwinding.
147	 */
148	static inline JSValue qjs_new_error2(JSContext *cx)
149	{
150	    JSAtom   stack;
151	    JSValue  error;
152	
153	    stack = JS_NewAtom(cx, "stack");
154	    if (stack == JS_ATOM_NULL) {
155	        return JS_EXCEPTION;
156	    }
157	
158	    error = JS_NewError(cx);
159	    if (JS_IsException(error)) {
160	        JS_FreeAtom(cx, stack);
161	        return JS_EXCEPTION;
162	    }
163	
164	    JS_DeleteProperty(cx, error, stack, 0);
165	    JS_FreeAtom(cx, stack);
166	
167	    return error;
168	}
